import { createClient } from "@/lib/supabase/server";
import {
  Trophy,
  Users,
  Gamepad2,
  BarChart3,
  TrendingUp,
  ShieldAlert,
} from "lucide-react";
import { Link } from "@/lib/i18n/routing";
import { getTranslations } from "next-intl/server";

export async function generateMetadata({
  params,
}: {
  params: Promise<{ locale: string }>;
}) {
  const { locale } = await params;
  const t = await getTranslations({ locale, namespace: "Metadata" });
  return { title: t("admin_dashboard") };
}

export default async function AdminDashboardPage() {
  const supabase = await createClient();

  // Fetch Global Stats
  const { count: userCount } = await supabase
    .from("profiles")
    .select("*", { count: "exact", head: true });
  const { count: tournamentCount } = await supabase
    .from("tournaments")
    .select("*", { count: "exact", head: true });
  const { count: gameCount } = await supabase
    .from("games")
    .select("*", { count: "exact", head: true });
  const { count: registrationCount } = await supabase
    .from("registrations")
    .select("*", { count: "exact", head: true });

  // Fetch Real Recent Activity
  const { data: recentRegistrations } = await supabase
    .from("registrations")
    .select("*, profiles(nickname), tournaments(name)")
    .order("created_at", { ascending: false })
    .limit(5);

  const stats = [
    {
      label: "Total Users",
      value: userCount || 0,
      icon: Users,
      color: "text-brand-primary",
      trend: "Global users",
    },
    {
      label: "Total Tournaments",
      value: tournamentCount || 0,
      icon: Trophy,
      color: "text-warning",
      trend: "Created arenas",
    },
    {
      label: "Game Library",
      value: gameCount || 0,
      icon: Gamepad2,
      color: "text-success",
      trend: "Supported titles",
    },
    {
      label: "Total Registrations",
      value: registrationCount || 0,
      icon: BarChart3,
      color: "text-info",
      trend: "Player entries",
    },
  ];

  return (
    <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-700">
      {/* HEADER */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
        <div>
          <div className="flex items-center gap-3 mb-2">
            <span className="h-2 w-2 rounded-full bg-brand-primary animate-pulse"></span>
            <span className="text-[10px] font-black text-brand-primary uppercase tracking-[0.4em]">
              Live Telemetry
            </span>
          </div>
          <h1 className="font-display text-5xl font-black uppercase tracking-tighter text-white">
            System Overview
          </h1>
          <p className="text-text-secondary mt-2 font-medium">
            Real-time platform metrics and global administration.
          </p>
        </div>
      </div>

      {/* STATS GRID */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
        {stats.map((stat, i) => (
          <div
            key={i}
            className="bg-[#0c0c0e] border border-white/5 rounded-[2.5rem] p-10 hover:border-brand-primary/30 transition-all group relative overflow-hidden shadow-2xl"
          >
            <div className="absolute top-0 right-0 p-8 opacity-5 group-hover:opacity-20 transition-all duration-700">
              <stat.icon className="h-24 w-24" />
            </div>
            <div className="flex items-center justify-between mb-6 relative z-10">
              <span className="text-[11px] text-text-tertiary font-black uppercase tracking-[0.2em]">
                {stat.label}
              </span>
              <stat.icon className={`h-5 w-5 ${stat.color}`} />
            </div>
            <div className="font-display text-5xl font-black text-white relative z-10 mb-2">
              {stat.value}
            </div>
            <div className="flex items-center gap-2 text-[10px] font-bold text-text-tertiary uppercase tracking-widest relative z-10">
              {stat.trend}
            </div>
          </div>
        ))}
      </div>

      {/* RECENT ACTIVITY */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
        <div className="lg:col-span-2 space-y-8">
          <div className="flex items-center justify-between">
            <h2 className="font-display text-2xl font-black uppercase tracking-tight text-white">
              Recent Registrations
            </h2>
            <Link
              href="/admin/reports"
              className="text-[10px] text-brand-primary font-black uppercase tracking-[0.2em] hover:text-white transition-colors"
            >
              View All Logs
            </Link>
          </div>
          <div className="bg-[#0c0c0e] border border-white/5 rounded-[3rem] overflow-hidden shadow-2xl">
            <div className="p-4 bg-white/2 border-b border-white/5 grid grid-cols-4 text-[10px] font-black uppercase tracking-widest text-text-tertiary px-10">
              <span>Player</span>
              <span>Tournament</span>
              <span>Applied At</span>
              <span className="text-right">Status</span>
            </div>
            <div className="divide-y divide-white/5">
              {recentRegistrations?.length === 0 ? (
                <div className="p-20 text-center text-text-tertiary uppercase font-black tracking-widest text-xs">
                  No activity yet
                </div>
              ) : (
                recentRegistrations?.map((reg) => (
                  <div
                    key={reg.id}
                    className="px-10 py-6 grid grid-cols-4 items-center hover:bg-white/2 transition-all"
                  >
                    <div className="flex items-center gap-3">
                      <div className="h-8 w-8 rounded-full bg-brand-primary/20 flex items-center justify-center text-brand-primary text-[10px] font-black uppercase">
                        {reg.profiles?.nickname?.charAt(0) || "P"}
                      </div>
                      <span className="text-sm font-black text-white">
                        {reg.profiles?.nickname}
                      </span>
                    </div>
                    <span className="text-xs font-bold text-text-secondary truncate">
                      {reg.tournaments?.name}
                    </span>
                    <span className="text-xs text-text-tertiary font-medium">
                      {new Date(reg.created_at).toLocaleDateString()}
                    </span>
                    <div className="text-right">
                      <span
                        className={`text-[9px] px-3 py-1 rounded-full font-black uppercase tracking-wider ${
                          reg.status === "approved"
                            ? "bg-success/10 text-success border border-success/20"
                            : reg.status === "pending"
                              ? "bg-warning/10 text-warning border border-warning/20"
                              : "bg-white/5 text-text-tertiary"
                        }`}
                      >
                        {reg.status}
                      </span>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>

        <div className="space-y-8">
          <h2 className="font-display text-2xl font-black uppercase tracking-tight text-white">
            System Tools
          </h2>
          <div className="space-y-4">
            {[
              {
                label: "Register Game",
                icon: Gamepad2,
                href: "/admin/games/new",
              },
              {
                label: "Platform Config",
                icon: BarChart3,
                href: "/admin/settings",
              },
              {
                label: "Global Audit",
                icon: ShieldAlert,
                href: "/admin/reports",
              },
            ].map((action, i) => (
              <Link key={i} href={action.href} className="block group">
                <div className="p-8 bg-white/2 border border-white/5 rounded-[2rem] hover:bg-brand-primary hover:border-brand-primary transition-all duration-500 shadow-xl">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-5">
                      <action.icon className="h-6 w-6 text-brand-primary group-hover:text-white transition-colors" />
                      <span className="font-black uppercase tracking-widest text-white">
                        {action.label}
                      </span>
                    </div>
                    <span className="text-2xl text-brand-primary group-hover:text-white transition-colors">
                      →
                    </span>
                  </div>
                </div>
              </Link>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { createClient } from "@/lib/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Gamepad2, Upload, CheckCircle2, Loader2, Save } from "lucide-react";
import Image from "next/image";

interface GameFormProps {
  initialData?: any;
  id?: string;
}

export function GameForm({ initialData, id }: GameFormProps) {
  const router = useRouter();
  const supabase = createClient();
  const [loading, setLoading] = useState(false);
  const [logoFile, setLogoFile] = useState<File | null>(null);
  const [coverFile, setCoverFile] = useState<File | null>(null);
  const [logoPreview, setLogoPreview] = useState<string>(
    initialData?.logo_url || "",
  );
  const [coverPreview, setCoverPreview] = useState<string>(
    initialData?.cover_url || "",
  );

  const isEdit = !!id;

  async function handleSubmit(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    setLoading(true);

    const formData = new FormData(e.currentTarget);
    const name = formData.get("name") as string;
    const slug = formData.get("slug") as string;
    const description = formData.get("description") as string;

    let logo_url = initialData?.logo_url || "";
    let cover_url = initialData?.cover_url || "";

    // Upload Logo if new file selected
    if (logoFile) {
      const { data } = await supabase.storage
        .from("game-assets")
        .upload(`logos/${Date.now()}-${logoFile.name}`, logoFile);
      if (data) logo_url = data.path;
    }

    // Upload Cover if new file selected
    if (coverFile) {
      const { data } = await supabase.storage
        .from("game-assets")
        .upload(`covers/${Date.now()}-${coverFile.name}`, coverFile);
      if (data) cover_url = data.path;
    }

    if (isEdit) {
      // Update
      const { error } = await supabase
        .from("games")
        .update({ name, slug, description, logo_url, cover_url })
        .eq("id", id);
      if (error) alert(error.message);
    } else {
      // Create
      const { error } = await supabase.from("games").insert({
        name,
        slug,
        description,
        logo_url,
        cover_url,
        is_active: true,
      });
      if (error) alert(error.message);
    }

    setLoading(false);
    router.push("/admin/games");
    router.refresh();
  }

  return (
    <form
      onSubmit={handleSubmit}
      className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-700"
    >
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
        <div className="lg:col-span-2 space-y-8 bg-[#0c0c0e] border border-white/5 p-10 rounded-[2.5rem] shadow-2xl">
          <div className="flex items-center gap-4 mb-4">
            <div className="h-12 w-12 rounded-xl bg-brand-primary/10 flex items-center justify-center text-brand-primary border border-brand-primary/20">
              <Gamepad2 className="h-6 w-6" />
            </div>
            <h2 className="font-display text-2xl font-black uppercase tracking-tight text-white">
              {isEdit ? "Update Metadata" : "Title Metadata"}
            </h2>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-3">
              <Label className="text-[10px] font-black uppercase tracking-[0.2em] text-text-tertiary">
                Game Name
              </Label>
              <Input
                name="name"
                defaultValue={initialData?.name}
                required
                className="bg-white/5 border-white/10 h-14 rounded-xl focus:border-brand-primary transition-all text-white font-bold"
              />
            </div>
            <div className="space-y-3">
              <Label className="text-[10px] font-black uppercase tracking-[0.2em] text-text-tertiary">
                Slug (URL friendly)
              </Label>
              <Input
                name="slug"
                defaultValue={initialData?.slug}
                required
                className="bg-white/5 border-white/10 h-14 rounded-xl focus:border-brand-primary transition-all text-white font-bold"
              />
            </div>
          </div>

          <div className="space-y-3">
            <Label className="text-[10px] font-black uppercase tracking-[0.2em] text-text-tertiary">
              Description
            </Label>
            <Textarea
              name="description"
              defaultValue={initialData?.description}
              className="bg-white/5 border-white/10 min-h-[150px] rounded-2xl focus:border-brand-primary transition-all text-white font-medium p-6"
            />
          </div>
        </div>

        <div className="space-y-8">
          <div className="bg-[#0c0c0e] border border-white/5 p-8 rounded-[2.5rem] shadow-xl">
            <Label className="text-[10px] font-black uppercase tracking-[0.2em] text-text-tertiary mb-4 block">
              Game Logo (PNG)
            </Label>
            <div className="relative h-40 border-2 border-dashed border-white/5 rounded-2xl flex flex-col items-center justify-center group hover:border-brand-primary transition-all cursor-pointer overflow-hidden">
              {logoFile || initialData?.logo_url ? (
                <div className="relative h-full w-full flex items-center justify-center bg-white/5">
                  {logoFile ? (
                    <div className="text-center">
                      <CheckCircle2 className="h-10 w-10 text-success mx-auto mb-2" />
                      <p className="text-[10px] font-bold text-white truncate px-4">
                        {logoFile.name}
                      </p>
                    </div>
                  ) : (
                    <Image
                      src={
                        initialData.logo_url.startsWith("http")
                          ? initialData.logo_url
                          : `${process.env.NEXT_PUBLIC_SUPABASE_URL}/storage/v1/object/public/game-assets/${initialData.logo_url}`
                      }
                      alt="Logo"
                      fill
                      className="object-contain p-4"
                    />
                  )}
                </div>
              ) : (
                <>
                  <Upload className="h-8 w-8 text-text-tertiary group-hover:text-brand-primary transition-colors mb-2" />
                  <span className="text-[10px] font-black uppercase tracking-widest text-text-tertiary">
                    Select Logo
                  </span>
                </>
              )}
              <input
                type="file"
                onChange={(e) => setLogoFile(e.target.files?.[0] || null)}
                className="absolute inset-0 opacity-0 cursor-pointer"
                accept="image/*"
              />
            </div>
          </div>

          <div className="bg-[#0c0c0e] border border-white/5 p-8 rounded-[2.5rem] shadow-xl">
            <Label className="text-[10px] font-black uppercase tracking-[0.2em] text-text-tertiary mb-4 block">
              Cover Image (Wide)
            </Label>
            <div className="relative h-40 border-2 border-dashed border-white/5 rounded-2xl flex flex-col items-center justify-center group hover:border-brand-primary transition-all cursor-pointer overflow-hidden">
              {coverFile || initialData?.cover_url ? (
                <div className="relative h-full w-full flex items-center justify-center">
                  {coverFile ? (
                    <div className="text-center">
                      <CheckCircle2 className="h-10 w-10 text-success mx-auto mb-2" />
                      <p className="text-[10px] font-bold text-white truncate px-4">
                        {coverFile.name}
                      </p>
                    </div>
                  ) : (
                    <Image
                      src={
                        initialData.cover_url.startsWith("http")
                          ? initialData.cover_url
                          : `${process.env.NEXT_PUBLIC_SUPABASE_URL}/storage/v1/object/public/game-assets/${initialData.cover_url}`
                      }
                      alt="Cover"
                      fill
                      className="object-cover opacity-50"
                    />
                  )}
                </div>
              ) : (
                <>
                  <Upload className="h-8 w-8 text-text-tertiary group-hover:text-brand-primary transition-colors mb-2" />
                  <span className="text-[10px] font-black uppercase tracking-widest text-text-tertiary">
                    Select Cover
                  </span>
                </>
              )}
              <input
                type="file"
                onChange={(e) => setCoverFile(e.target.files?.[0] || null)}
                className="absolute inset-0 opacity-0 cursor-pointer"
                accept="image/*"
              />
            </div>
          </div>

          <Button
            type="submit"
            disabled={loading}
            className="w-full bg-brand-primary text-white hover:bg-white hover:text-black py-8 rounded-2xl font-black uppercase tracking-widest text-base shadow-[0_0_30px_rgba(244,0,9,0.4)] transition-all"
          >
            {loading ? (
              <Loader2 className="h-6 w-6 animate-spin" />
            ) : isEdit ? (
              <>
                <Save className="mr-2 h-5 w-5" /> Save Changes
              </>
            ) : (
              "Register Title"
            )}
          </Button>
        </div>
      </div>
    </form>
  );
}

import { createClient } from "@/lib/supabase/server";
import {
  Users,
  Shield,
  ShieldCheck,
  Mail,
  Calendar,
  Search,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { getTranslations } from "next-intl/server";

export async function generateMetadata({
  params,
}: {
  params: Promise<{ locale: string }>;
}) {
  const { locale } = await params;
  const t = await getTranslations({ locale, namespace: "Metadata" });
  return { title: t("admin_users") };
}

export default async function AdminUsersPage() {
  const supabase = await createClient();
  const { data: profiles } = await supabase
    .from("profiles")
    .select("*")
    .order("created_at", { ascending: false })
    .limit(20);

  return (
    <div className="space-y-12 animate-in fade-in duration-700">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
        <div>
          <h1 className="font-display text-5xl font-black uppercase tracking-tighter text-white">
            User Directory
          </h1>
          <p className="text-text-secondary mt-2 font-medium">
            Monitor and manage all platform participants and organizers.
          </p>
        </div>
        <div className="relative w-full md:w-96">
          <Search className="absolute left-6 top-1/2 -translate-y-1/2 h-5 w-5 text-text-tertiary" />
          <Input
            className="bg-white/5 border-white/5 pl-14 h-16 rounded-2xl text-white font-bold uppercase tracking-widest text-xs focus:border-brand-primary transition-all shadow-2xl"
            placeholder="Search nickname or email..."
          />
        </div>
      </div>

      {/* USERS LIST */}
      <div className="bg-[#0c0c0e] border border-white/5 rounded-[3rem] overflow-hidden shadow-2xl">
        <div className="p-6 bg-white/2 border-b border-white/5 grid grid-cols-4 text-[10px] font-black uppercase tracking-widest text-text-tertiary px-10">
          <span>Profile</span>
          <span>Role</span>
          <span>Joined Date</span>
          <span className="text-right">Action</span>
        </div>
        <div className="divide-y divide-white/5">
          {profiles?.map((profile) => (
            <div
              key={profile.id}
              className="px-10 py-8 grid grid-cols-4 items-center hover:bg-white/2 transition-all group"
            >
              <div className="flex items-center gap-4">
                <div className="h-12 w-12 rounded-2xl bg-brand-subtle flex items-center justify-center text-brand-primary border border-brand-primary/10 group-hover:scale-110 transition-transform">
                  <Users className="h-6 w-6" />
                </div>
                <div className="truncate">
                  <div className="font-black text-white uppercase tracking-tight truncate">
                    {profile.nickname}
                  </div>
                  <div className="text-[10px] text-text-tertiary uppercase font-bold tracking-widest truncate">
                    {profile.id.slice(0, 8)}
                  </div>
                </div>
              </div>

              <div>
                <span
                  className={`text-[9px] px-4 py-1.5 rounded-full font-black uppercase tracking-widest flex items-center gap-2 w-fit ${
                    profile.role === "admin"
                      ? "bg-brand-primary text-white"
                      : profile.role === "organizer"
                        ? "bg-success/10 text-success border border-success/20"
                        : "bg-white/5 text-text-tertiary"
                  }`}
                >
                  {profile.role === "admin" ? (
                    <ShieldCheck className="h-3 w-3" />
                  ) : profile.role === "organizer" ? (
                    <Shield className="h-3 w-3" />
                  ) : null}
                  {profile.role}
                </span>
              </div>

              <div className="flex items-center gap-2 text-xs text-text-tertiary font-medium">
                <Calendar className="h-3.5 w-3.5" />
                {new Date(profile.created_at).toLocaleDateString()}
              </div>

              <div className="text-right">
                <Button
                  variant="ghost"
                  className="text-[10px] font-black uppercase tracking-widest text-text-tertiary hover:text-brand-primary transition-colors"
                >
                  Manage
                </Button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

import { createClient } from "@/lib/supabase/server";
import { Link } from "@/lib/i18n/routing";
import { Trophy, Folder, Users, Swords, Plus } from "lucide-react";
import { Button } from "@/components/ui/button";
import { getTranslations } from "next-intl/server";

export async function generateMetadata({ params }: any) {
  const { locale } = await params;
  const t = await getTranslations({ locale, namespace: "Metadata" });
  return { title: t("organizer_dashboard") };
}

export default async function OrganizerDashboard() {
  const t = await getTranslations("Organizer.dashboard");
  const common = await getTranslations("Common");
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();

  // Fetch Stats
  const { count: projectCount } = await supabase
    .from("projects")
    .select("*", { count: "exact", head: true })
    .eq("owner_id", user?.id);

  const { count: tournamentCount } = await supabase
    .from("tournaments")
    .select("*, projects!inner(owner_id)", { count: "exact", head: true })
    .eq("projects.owner_id", user?.id);

  const { count: participantCount } = await supabase
    .from("participants")
    .select("*, tournaments!inner(projects!inner(owner_id))", {
      count: "exact",
      head: true,
    })
    .eq("tournaments.projects.owner_id", user?.id);

  const { data: recentTournaments } = await supabase
    .from("tournaments")
    .select(
      "*, projects!inner(name, owner_id), games(name), participants(count)",
    )
    .eq("projects.owner_id", user?.id)
    .order("created_at", { ascending: false })
    .limit(5);

  return (
    <div className="space-y-10 animate-in fade-in duration-700">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4">
        <div>
          <h1 className="font-display text-4xl font-black uppercase tracking-tighter text-white">
            {t("title")}
          </h1>
          <p className="text-text-secondary mt-1 font-medium">
            {t("subtitle")}
          </p>
        </div>
        <Link href="/organizer/projects/new">
          <Button className="bg-brand-primary text-white hover:bg-white hover:text-black hover:shadow-[0_0_20px_rgba(255,255,255,0.1)] transition-all font-bold uppercase tracking-widest px-8">
            <Plus className="mr-2 h-4 w-4" /> {common("manage")}
          </Button>
        </Link>
      </div>

      {/* STATS CARDS */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        {[
          {
            label: t("stats.projects"),
            value: projectCount || 0,
            icon: Folder,
            color: "text-brand-primary",
          },
          {
            label: t("stats.tournaments"),
            value: tournamentCount || 0,
            icon: Trophy,
            color: "text-warning",
          },
          {
            label: t("stats.players"),
            value: participantCount || 0,
            icon: Users,
            color: "text-success",
          },
          {
            label: t("stats.matches"),
            value: 0,
            icon: Swords,
            color: "text-info",
          },
        ].map((stat, i) => (
          <div
            key={i}
            className="bg-bg-secondary border border-white/5 rounded-[2rem] p-8 hover:border-brand-primary/30 transition-all group relative overflow-hidden"
          >
